+fn scalar_for_label<'a>(series: &'a Series, label: &IndexLabel) -> Option<&'a Scalar> {
+    series
+        .index()
+        .labels()
+        .iter()
+        .zip(series.values())
+        .find_map(|(candidate, value)| (candidate == label).then_some(value))
+}
